SELECT SUM(total_units) AS total_residential_units
  FROM residential_units
 WHERE neighborhood_id = 0;

SELECT neighborhood_id, service_type, service_website
FROM city_services
WHERE service_type = 'Healthcare';

SELECT neighborhood_name
FROM neighborhoods
ORDER BY neighborhood_name;

SELECT total_units
FROM residential_units
WHERE neighborhood_id = 1;

SELECT postal_code, borough
FROM postal_codes
WHERE postal_code = '0';

SELECT MAX(average_income) AS max_income
FROM geographical_data
WHERE neighborhood_id = 1;
